/bin/bash -lc "clickhouse-client --multiquery <<'SQL'
DROP VIEW IF EXISTS analytics.mv_rollup_hourly;
DROP VIEW IF EXISTS analytics.mv_rollup_daily;
DROP VIEW IF EXISTS analytics.mv_rollup_monthly;
DROP TABLE IF EXISTS analytics.rollup_hourly;
DROP TABLE IF EXISTS analytics.rollup_daily;
DROP TABLE IF EXISTS analytics.rollup_monthly;

CREATE TABLE analytics.rollup_hourly (
  hour DateTime,
  event_count UInt64
) ENGINE = SummingMergeTree()
ORDER BY hour;

CREATE TABLE analytics.rollup_daily (
  day Date,
  event_count UInt64
) ENGINE = SummingMergeTree()
ORDER BY day;

CREATE TABLE analytics.rollup_monthly (
  month Date,
  event_count UInt64
) ENGINE = SummingMergeTree()
ORDER BY month;

CREATE MATERIALIZED VIEW analytics.mv_rollup_hourly
TO analytics.rollup_hourly AS
SELECT
  toStartOfHour(event_ts) AS hour,
  count() AS event_count
FROM analytics.raw_events
GROUP BY hour;

CREATE MATERIALIZED VIEW analytics.mv_rollup_daily
TO analytics.rollup_daily AS
SELECT
  toDate(event_ts) AS day,
  count() AS event_count
FROM analytics.raw_events
GROUP BY day;

CREATE MATERIALIZED VIEW analytics.mv_rollup_monthly
TO analytics.rollup_monthly AS
SELECT
  toStartOfMonth(event_ts) AS month,
  count() AS event_count
FROM analytics.raw_events
GROUP BY month;

INSERT INTO analytics.rollup_hourly
SELECT toStartOfHour(event_ts) AS hour, count() AS event_count
FROM analytics.raw_events
GROUP BY hour;

INSERT INTO analytics.rollup_daily
SELECT toDate(event_ts) AS day, count() AS event_count
FROM analytics.raw_events
GROUP BY day;

INSERT INTO analytics.rollup_monthly
SELECT toStartOfMonth(event_ts) AS month, count() AS event_count
FROM analytics.raw_events
GROUP BY month;
SQL"

